examples.original_ir:
define i1 @test(i1 %cond, i8 %a, i8 %b) {
  %cmp1 = icmp samesign ult i8 %a, %b
  %cmp2 = icmp uge i8 %a, %b
  %sel = select i1 %cond, i1 %cmp2, i1 %cmp1
  ret i1 %sel
}

examples.optimized_ir:
define i1 @test(i1 %cond, i8 %a, i8 %b) {
  %cmp1 = icmp samesign ult i8 %a, %b
  %sel = xor i1 %cond, %cmp1
  ret i1 %sel
}
